// أضف هذه الدوال في بداية ملف main.min.js أو قم بتعديل الدوال الموجودة

function showErrorPopup() {
    var errorContainer = document.querySelector(".error-container");
    if(errorContainer) {
        errorContainer.classList.add("active");
        setTimeout(function() {
            errorContainer.classList.add("zoom");
        }, 10);
        setTimeout(function() {
            hideErrorPopup();
        }, 3000);
    }
}

function hideErrorPopup() {
    var errorContainer = document.querySelector(".error-container");
    if(errorContainer) {
        errorContainer.classList.remove("active");
        errorContainer.classList.remove("zoom");
    }
}

function toArabicError(errorText) {
    var errorMessages = {
        "user not found": "لقد أدخلت الكرت بطريقة غير صحيحة، الرجاء المحاولة مرة أخرى",
        "invalid password": "تأكد من كتابة كلمة المرور بشكل صحيح",
        "uptime limit reached": "عذراً لقد انتهى الوقت المتاح لك",
        "traffic limit": "لقد انتهى رصيد هذا الحساب",
        "invalid username or password": "لقد أدخلت اسم المستخدم بطريقة غير صحيحة",
        "no valid profile found": "لقد انتهت صلاحية هذا الكرت",
        "server is not responding": "هذا الحساب غير موجود, يرجى التأكد والمحاولة مرة أخرى"
    };
    
    for(var key in errorMessages) {
        if(errorText.toLowerCase().includes(key)) {
            return errorMessages[key];
        }
    }
    return "حدث خطأ: " + errorText;
}

// تأكد من أن دالة onLoginError موجودة وتعمل بشكل صحيح
function onLoginError(errorData) {
    var loginSubmit = document.querySelector(".login-submit");
    if(loginSubmit) {
        loginSubmit.classList.remove("success");
        loginSubmit.classList.remove("processing");
    }
    
    if(!errorData.error.includes("already authorizing, retry later")) {
        var errorElement = document.getElementById("error");
        if(errorElement) {
            errorElement.innerText = toArabicError(errorData.error);
        }
        showErrorPopup();
        
        if(hotspotConfig["enable-hot-blocker"] === 1) {
            var failCount = incrementCounter(errorData);
            checkFailsCount(errorData, failCount);
        }
        clearCookies();
    }
}
